import Link from "next/link";
import type { PageAction } from "@/types/site";

type ButtonLinkProps = {
  action: PageAction;
};

export function ButtonLink({ action }: ButtonLinkProps) {
  const isPrimary = action.variant !== "secondary";
  const className = isPrimary
    ? "inline-flex items-center justify-center rounded-full bg-[var(--text-primary)] px-6 py-3 text-sm font-semibold text-white transition hover:opacity-90"
    : "inline-flex items-center justify-center rounded-full border border-[var(--border)] bg-white/70 px-6 py-3 text-sm font-semibold text-[var(--text-primary)] transition hover:bg-[var(--surface-alt)]";

  return (
    <Link className={className} href={action.href}>
      {action.label}
    </Link>
  );
}
